1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import {
3		Check,
4		ChevronDown,
5		ChevronRight,
6		CopyPlus,
7		GitBranch,
8		History,
9		Loader2,
10		PanelLeftClose,
11		PanelLeftOpen,
12		Plus,
13		Search,
14	} from "lucide-react";
15	import { sessions } from "../hooks/keating-storage";
16	import type { SessionMetadata } from "../types/session";
17	import { buildSessionTree, flattenSessionTree } from "./session-tree";
18	
19	const TREE_COLLAPSED_STORAGE_KEY = "keating:session-tree-collapsed";
20	const MD_BREAKPOINT = 768;
21	
22	const SIDEBAR_MIN_W = 288;
23	const SIDEBAR_MAX_W = 640;
24	const SIDEBAR_DEFAULT_W = 360;
25	const SIDEBAR_W_KEY = "keating_session_sidebar_width";
26	
27	interface SessionSidebarProps {
28		activeSessionId?: string;
29		forkingSessionId?: string | null;
30		forkedSessionId?: string | null;
31		collapsed?: boolean;
32		onCollapsedChange?: (next: boolean) => void;
33		onLoad: (sessionId: string) => void | Promise<void>;
34		onFork: (sessionId: string) => void | Promise<void>;
35		onOpenSessions: () => void;
36		mobileOpen?: boolean;
37		onMobileClose?: () => void;
38		onNewSession?: () => void;
39	}
40	
41	function formatDate(isoString: string) {
42		const date = new Date(isoString);
43		const now = new Date();
44		const days = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24));
45		if (days === 0) return "Today";
46		if (days === 1) return "Yesterday";
47		if (days < 7) return `${days}d ago`;
48		return date.toLocaleDateString();
49	}
50	
51	function readCollapsedTreeNodes(): Set<string> {
52		if (typeof localStorage === "undefined") return new Set();
53		try {
54			const raw = localStorage.getItem(TREE_COLLAPSED_STORAGE_KEY);
55			if (!raw) return new Set();
56			const parsed = JSON.parse(raw);
57			if (!Array.isArray(parsed)) return new Set();
58			return new Set(parsed.filter((value): value is string => typeof value === "string"));
59		} catch {
60			return new Set();
61		}
62	}
63	
64	function writeCollapsedTreeNodes(set: ReadonlySet<string>) {
65		if (typeof localStorage === "undefined") return;
66		try {
67			localStorage.setItem(TREE_COLLAPSED_STORAGE_KEY, JSON.stringify([...set]));
68		} catch {
69			// localStorage may be full or blocked; ignore.
70		}
71	}
72	
73	function loadSidebarWidth(): number {
74		if (typeof localStorage === "undefined") return SIDEBAR_DEFAULT_W;
75		try {
76			const raw = localStorage.getItem(SIDEBAR_W_KEY);
77			if (!raw) return SIDEBAR_DEFAULT_W;
78			const parsed = parseInt(raw, 10);
79			if (isNaN(parsed) || parsed < SIDEBAR_MIN_W || parsed > SIDEBAR_MAX_W) return SIDEBAR_DEFAULT_W;
80			return parsed;
81		} catch {
82			return SIDEBAR_DEFAULT_W;
83		}
84	}
85	
86	function saveSidebarWidth(value: number) {
87		try {
88			localStorage.setItem(SIDEBAR_W_KEY, String(value));
89		} catch {
90			/* noop */
91		}
92	}
93	
94	export function SessionSidebar({
95		activeSessionId,
96		forkingSessionId,
97		forkedSessionId,
98		collapsed = false,
99		onCollapsedChange,
100		onLoad,
101		onFork,
102		onOpenSessions,
103		mobileOpen = false,
104		onMobileClose,
105		onNewSession,
106	}: SessionSidebarProps) {
107		const [items, setItems] = useState<SessionMetadata[]>([]);
108		const [loading, setLoading] = useState(false);
109		const [query, setQuery] = useState("");
110		const [forkedSourceSessionId, setForkedSourceSessionId] = useState<string | null>(null);
111		const [collapsedNodes, setCollapsedNodes] = useState<Set<string>>(() => readCollapsedTreeNodes());
112		const [isDesktop, setIsDesktop] = useState(() =>
113			typeof window !== "undefined"
114				? window.matchMedia(`(min-width: ${MD_BREAKPOINT}px)`).matches
115				: true,
116		);
117		const [sidebarWidth, setSidebarWidth] = useState(loadSidebarWidth);
118		const dragState = useRef({ active: false, startX: 0, startWidth: 0 });
119	
120		useEffect(() => {
121			if (typeof window === "undefined") return;
122			const mq = window.matchMedia(`(min-width: ${MD_BREAKPOINT}px)`);
123			const sync = () => setIsDesktop(mq.matches);
124			mq.addEventListener("change", sync);
125			return () => mq.removeEventListener("change", sync);
126		}, []);
127	
128		const isSearching = query.trim().length > 0;
129	
130		const visibleItems = useMemo(() => {
131			const normalizedQuery = query.trim().toLowerCase();
132			const filtered = items.filter((session) => {
133				if (!normalizedQuery) return true;
134				return [session.title, session.preview, formatDate(session.lastModified)]
135					.some((value) => value.toLowerCase().includes(normalizedQuery));
136			});
137			if (normalizedQuery) {
138				return filtered
139					.map((session) => ({ session, children: [], depth: 0 }))
140					.sort((left, right) => right.session.lastModified.localeCompare(left.session.lastModified))
141					.slice(0, 40);
142			}
143			return flattenSessionTree(buildSessionTree(filtered), collapsedNodes).slice(0, 80);
144		}, [items, query, collapsedNodes]);
145	
146		const reload = async () => {
147			setLoading(true);
148			try {
149				setItems((await sessions.getAllMetadata()) as SessionMetadata[]);
150			} finally {
151				setLoading(false);
152			}
153		};
154	
155		useEffect(() => {
156			void reload();
157			const onChanged = () => void reload();
158			window.addEventListener("keating:sessions-changed", onChanged);
159			return () => window.removeEventListener("keating:sessions-changed", onChanged);
160		}, []);
161	
162		const toggleNode = useCallback((sessionId: string) => {
163			setCollapsedNodes((current) => {
164				const next = new Set(current);
165				if (next.has(sessionId)) {
166					next.delete(sessionId);
167				} else {
168					next.add(sessionId);
169				}
170				writeCollapsedTreeNodes(next);
171				return next;
172			});
173		}, []);
174	
175		const forkSession = async (sessionId: string) => {
176			await onFork(sessionId);
177			setForkedSourceSessionId(sessionId);
178			window.setTimeout(() => {
179				setForkedSourceSessionId((current) => current === sessionId ? null : current);
180			}, 1800);
181		};
182	
183		/* ── Resize handlers ── */
184		const handleResizeStart = useCallback((e: React.MouseEvent | React.TouchEvent) => {
185			e.preventDefault();
186			const clientX = "touches" in e ? e.touches[0].clientX : e.clientX;
187			dragState.current = { active: true, startX: clientX, startWidth: sidebarWidth };
188	
189			const onMove = (moveEvent: MouseEvent | TouchEvent) => {
190				if (!dragState.current.active) return;
191				const moveX = "touches" in moveEvent ? moveEvent.touches[0].clientX : moveEvent.clientX;
192				const delta = moveX - dragState.current.startX;
193				const next = Math.min(SIDEBAR_MAX_W, Math.max(SIDEBAR_MIN_W, dragState.current.startWidth + delta));
194				setSidebarWidth(next);
195			};
196	
197			const onUp = () => {
198				if (!dragState.current.active) return;
199				dragState.current.active = false;
200				document.body.style.cursor = "";
201				document.body.style.userSelect = "";
202				window.removeEventListener("mousemove", onMove);
203				window.removeEventListener("mouseup", onUp);
204				window.removeEventListener("touchmove", onMove);
205				window.removeEventListener("touchend", onUp);
206				setSidebarWidth((w) => {
207					saveSidebarWidth(w);
208					return w;
209				});
210			};
211	
212			document.body.style.cursor = "col-resize";
213			document.body.style.userSelect = "none";
214			window.addEventListener("mousemove", onMove);
215			window.addEventListener("mouseup", onUp);
216			window.addEventListener("touchmove", onMove, { passive: false });
217			window.addEventListener("touchend", onUp);
218		}, [sidebarWidth]);
219	
220		/* ── Mobile drawer ── */
221		if (!isDesktop) {
222			if (!mobileOpen) return null;
223			return (
224				<>
225					<div
226						className="fixed inset-0 z-40 bg-black/45"
227						onClick={onMobileClose}
228						aria-hidden="true"
229					/>
230					<aside className="session-sidebar fixed inset-y-0 left-0 z-50 flex w-[min(22rem,85vw)] flex-col border-r-2 border-border bg-background">
231						<header className="border-b border-border px-4 py-4">
232							<div className="flex items-start justify-between gap-3">
233								<div className="min-w-0">
234									<div className="flex items-center gap-2 text-sm font-semibold">
235										<History size={15} />
236										Sessions
237									</div>
238									<p className="mt-1 text-xs leading-5 text-muted-foreground">
239										Search, fork, rename, or load a previous conversation
240									</p>
241								</div>
242								<div className="flex shrink-0 items-center gap-1">
243									<button
244										type="button"
245										className="inline-flex h-8 shrink-0 items-center justify-center rounded-md border border-border px-2 text-xs hover:bg-accent"
246										onClick={onOpenSessions}
247									>
248										Manage
249									</button>
250									{onMobileClose ? (
251										<button
252											type="button"
253											className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md border border-border text-muted-foreground hover:bg-accent hover:text-accent-foreground"
254											title="Close sessions panel"
255											aria-label="Close sessions panel"
256											onClick={onMobileClose}
257										>
258											<PanelLeftClose size={14} />
259										</button>
260									) : null}
261								</div>
262							</div>
263							{onNewSession ? (
264								<button
265									type="button"
266									className="mt-3 inline-flex min-h-12 w-full items-center justify-center gap-2 rounded-lg border border-primary bg-primary text-sm font-semibold text-primary-foreground transition-colors active:bg-primary/90"
267									onClick={() => {
268										onNewSession();
269										onMobileClose?.();
270									}}
271								>
272									<Plus size={18} />
273									New session
274								</button>
275							) : null}
276							<label className="mt-3 flex min-h-11 items-center gap-2 rounded-md border border-border bg-background px-3 text-xs">
277								<Search size={14} className="shrink-0 text-muted-foreground" />
278								<input
279									className="min-w-0 flex-1 bg-transparent py-2.5 outline-none placeholder:text-muted-foreground"
280									value={query}
281									placeholder="Search sessions"
282									onChange={(event) => setQuery(event.target.value)}
283								/>
284							</label>
285						</header>
286						<div className="min-h-0 flex-1 overflow-y-auto p-3">
287							{loading && items.length === 0 ? (
288								<div className="flex items-center justify-center gap-2 py-8 text-xs text-muted-foreground">
289									<Loader2 size={14} className="animate-spin" />
290									Loading
291								</div>
292							) : visibleItems.length === 0 ? (
293								<div className="px-2 py-8 text-center text-xs text-muted-foreground">
294									No sessions yet
295								</div>
296							) : (
297								<ul className="space-y-2" role="tree" aria-label="Session tree">
298									{visibleItems.map(({ session, depth, children }) => {
299										const active = session.id === activeSessionId;
300										const forking = session.id === forkingSessionId;
301										const justForkedSource = session.id === forkedSourceSessionId;
302										const justForked = session.id === forkedSessionId;
303										const hasChildren = children.length > 0;
304										const expanded = hasChildren && !collapsedNodes.has(session.id);
305										const showToggle = hasChildren && !isSearching;
306										return (
307											<li
308												key={session.id}
309												role="treeitem"
310												aria-level={depth + 1}
311												aria-expanded={hasChildren ? expanded : undefined}
312												className={justForked ? "session-fork-arrive" : undefined}
313												style={{ marginLeft: `${Math.min(depth, 5) * 0.9}rem` }}
314											>
315												<div
316													className={`group flex min-w-0 items-start gap-1 rounded-lg border p-3 transition-colors ${
317														active
318															? "border-primary bg-primary/10 text-primary"
319															: "border-border text-foreground hover:bg-muted/40"
320													}`}
321												>
322													{showToggle ? (
323														<button
324															type="button"
325															className="mt-0.5 inline-flex h-5 w-5 shrink-0 items-center justify-center rounded text-muted-foreground hover:bg-accent hover:text-accent-foreground"
326															title={expanded ? "Collapse forks" : "Expand forks"}
327															aria-label={expanded ? `Collapse ${children.length} fork${children.length === 1 ? "" : "s"}` : `Expand ${children.length} fork${children.length === 1 ? "" : "s"}`}
328															onClick={() => toggleNode(session.id)}
329														>
330															{expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
331														</button>
332													) : (
333														<span aria-hidden="true" className="mt-0.5 inline-block h-5 w-5 shrink-0" />
334													)}
335													<button
336														type="button"
337														className="min-w-0 flex-1 text-left"
338														onClick={() => void onLoad(session.id)}
339													>
340														<div className="flex min-w-0 items-center gap-2">
341															{session.parentSessionId ? (
342																<GitBranch size={13} className="shrink-0 text-primary" />
343															) : null}
344															<span className="truncate text-sm font-medium">{session.title}</span>
345															{hasChildren ? (
346																<span className="shrink-0 rounded bg-muted px-1.5 py-0.5 text-[10px] text-muted-foreground">
347																	{children.length}
348																</span>
349															) : null}
350															{justForkedSource ? (
351																	<span className="shrink-0 rounded bg-primary px-1.5 py-0.5 text-[10px] text-primary-foreground">
352																		Forked
353																	</span>
354																) : null}
355														</div>
356														<p className="mt-2 overflow-hidden text-xs leading-5 text-muted-foreground [display:-webkit-box] [-webkit-box-orient:vertical] [-webkit-line-clamp:2]">
357															{session.preview || "No preview saved"}
358														</p>
359														<div className="mt-3 flex flex-wrap items-center gap-2 text-[11px] text-muted-foreground">
360															<span>{session.parentSessionId ? "Fork | " : ""}{formatDate(session.lastModified)}</span>
361															<span aria-hidden="true">|</span>
362															<span>{session.messageCount} messages</span>
363														</div>
364													</button>
365													<button
366														type="button"
367														className={`inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md text-muted-foreground hover:bg-accent hover:text-accent-foreground disabled:opacity-50 group-hover:opacity-100 ${
368															justForkedSource ? "text-primary opacity-100" : "opacity-0"
369														}`}
370														title={justForkedSource ? "Session forked" : "Fork session"}
371														aria-label={justForkedSource ? "Session forked" : "Fork session"}
372														disabled={forking}
373														onClick={() => void forkSession(session.id)}
374													>
375														{forking ? (
376															<Loader2 size={12} className="animate-spin" />
377														) : justForkedSource ? (
378															<Check size={12} />
379														) : (
380															<CopyPlus size={12} />
381														)}
382													</button>
383												</div>
384											</li>
385										);
386									})}
387								</ul>
388							)}
389						</div>
390					</aside>
391				</>
392			);
393		}
394	
395		/* ── Desktop collapsed strip ── */
396		if (collapsed) {
397			return (
398				<aside className="session-sidebar flex w-14 shrink-0 flex-col items-center gap-3 border-r-2 border-border bg-background py-3">
399					<button
400						type="button"
401						className="inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-accent hover:text-accent-foreground"
402						title="Expand sessions panel"
403						aria-label="Expand sessions panel"
404						onClick={() => onCollapsedChange?.(false)}
405					>
406						<PanelLeftOpen size={16} />
407					</button>
408					<div className="my-1 h-px w-8 bg-border" />
409					{onNewSession ? (
410						<button
411							type="button"
412							className="inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-accent hover:text-accent-foreground"
413							title="New session"
414							aria-label="New session"
415							onClick={onNewSession}
416						>
417							<Plus size={16} />
418						</button>
419					) : null}
420				</aside>
421			);
422		}
423	
424		/* ── Desktop expanded sidebar ── */
425		return (
426			<aside className="session-sidebar relative flex shrink-0 flex-col border-r-2 border-border bg-background" style={{ width: `${sidebarWidth}px` }}>
427				{/* Resize handle — right edge drag bar */}
428				<div
429					className="group absolute inset-y-0 right-0 z-10 flex w-2 cursor-col-resize items-center justify-center"
430					onMouseDown={handleResizeStart}
431					onTouchStart={handleResizeStart}
432				>
433					<div className="h-8 w-0.5 rounded-full bg-border opacity-0 transition-opacity group-hover:opacity-100 group-active:opacity-100" />
434				</div>
435	
436				<header className="border-b border-border px-4 py-4">
437					<div className="flex items-start gap-3">
438						<div className="flex shrink-0 items-center gap-1">
439							{onCollapsedChange ? (
440								<button
441									type="button"
442									className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md border border-border text-muted-foreground hover:bg-accent hover:text-accent-foreground"
443									title="Collapse sessions panel"
444									aria-label="Collapse sessions panel"
445									onClick={() => onCollapsedChange(true)}
446								>
447									<PanelLeftClose size={14} />
448								</button>
449							) : null}
450							<button
451								type="button"
452								className="inline-flex h-8 shrink-0 items-center justify-center rounded-md border border-border px-2 text-xs hover:bg-accent"
453								onClick={onOpenSessions}
454							>
455								Manage
456							</button>
457						</div>
458						<div className="min-w-0 flex-1 text-right">
459							<div className="flex items-center justify-end gap-2 text-sm font-semibold">
460								Sessions
461								<History size={15} />
462							</div>
463							<p className="mt-1 text-xs leading-5 text-muted-foreground">
464								Search, fork, rename, or load a previous conversation
465							</p>
466						</div>
467					</div>
468					{onNewSession ? (
469						<button
470							type="button"
471							className="mt-3 inline-flex h-9 w-full items-center justify-center gap-2 rounded-md border border-primary bg-primary text-sm font-semibold text-primary-foreground transition-colors hover:bg-primary/90"
472							onClick={onNewSession}
473						>
474							<Plus size={16} />
475							New session
476						</button>
477					) : null}
478					<label className="mt-3 flex min-h-9 items-center gap-2 rounded-md border border-border bg-background px-3 text-xs">
479						<Search size={14} className="shrink-0 text-muted-foreground" />
480						<input
481							className="min-w-0 flex-1 bg-transparent py-2 outline-none placeholder:text-muted-foreground"
482							value={query}
483							placeholder="Search sessions"
484							onChange={(event) => setQuery(event.target.value)}
485						/>
486					</label>
487				</header>
488				<div className="min-h-0 flex-1 overflow-y-auto p-3">
489					{loading && items.length === 0 ? (
490						<div className="flex items-center justify-center gap-2 py-8 text-xs text-muted-foreground">
491							<Loader2 size={14} className="animate-spin" />
492							Loading
493						</div>
494					) : visibleItems.length === 0 ? (
495						<div className="px-2 py-8 text-center text-xs text-muted-foreground">
496							No sessions yet
497						</div>
498					) : (
499						<ul
500							className="space-y-2"
501							role="tree"
502							aria-label="Session tree"
503						>
504							{visibleItems.map(({ session, depth, children }) => {
505								const active = session.id === activeSessionId;
506								const forking = session.id === forkingSessionId;
507								const justForkedSource = session.id === forkedSourceSessionId;
508								const justForked = session.id === forkedSessionId;
509								const hasChildren = children.length > 0;
510								const expanded = hasChildren && !collapsedNodes.has(session.id);
511								const showToggle = hasChildren && !isSearching;
512								return (
513									<li
514										key={session.id}
515										role="treeitem"
516										aria-level={depth + 1}
517										aria-expanded={hasChildren ? expanded : undefined}
518										className={justForked ? "session-fork-arrive" : undefined}
519										style={{ marginLeft: `${Math.min(depth, 5) * 0.9}rem` }}
520									>
521										<div
522											className={`group flex min-w-0 items-start gap-1 rounded-lg border p-3 transition-colors ${
523												active
524													? "border-primary bg-primary/10 text-primary"
525													: "border-border text-foreground hover:bg-muted/40"
526											}`}
527										>
528											{showToggle ? (
529												<button
530													type="button"
531													className="mt-0.5 inline-flex h-5 w-5 shrink-0 items-center justify-center rounded text-muted-foreground hover:bg-accent hover:text-accent-foreground"
532													title={expanded ? "Collapse forks" : "Expand forks"}
533													aria-label={expanded ? `Collapse ${children.length} fork${children.length === 1 ? "" : "s"}` : `Expand ${children.length} fork${children.length === 1 ? "" : "s"}`}
534													onClick={() => toggleNode(session.id)}
535												>
536													{expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
537												</button>
538											) : (
539												<span aria-hidden="true" className="mt-0.5 inline-block h-5 w-5 shrink-0" />
540											)}
541											<button
542												type="button"
543												className="min-w-0 flex-1 text-left"
544												onClick={() => void onLoad(session.id)}
545											>
546												<div className="flex min-w-0 items-center gap-2">
547													{session.parentSessionId ? (
