import { useEffect, useRef, useState } from "react";
import {
	Check,
	GitBranch,
	Loader2,
	MoreVertical,
	Pencil,
	Trash2,
	X,
} from "lucide-react";
import type { SessionMetadata } from "../types/session";
import type { SessionTreeNode } from "./session-tree";

export interface ForkMapCardProps {
	root: SessionTreeNode;
	activeSessionId?: string;
	forkingSessionId?: string | null;
	onLoad: (sessionId: string) => void | Promise<void>;
	onFork: (sessionId: string) => void | Promise<void>;
	onRename: (sessionId: string, title: string) => void | Promise<void>;
	onDelete: (sessionId: string) => void | Promise<void>;
}

interface Row {
	session: SessionMetadata;
	depth: number;
	/** For each ancestor connector column, whether its vertical rail continues. */
	ancestorHasNext: boolean[];
	isLast: boolean;
}

function flattenWithGuides(root: SessionTreeNode): Row[] {
	const rows: Row[] = [];
	const walk = (node: SessionTreeNode, depth: number, ancestorHasNext: boolean[], isLast: boolean) => {
		rows.push({ session: node.session, depth, ancestorHasNext, isLast });
		node.children.forEach((child, index) => {
			const childIsLast = index === node.children.length - 1;
			// Only nodes at depth >= 1 own an elbow column that becomes an
			// ancestor rail for their descendants.
			const nextAncestors = depth >= 1 ? [...ancestorHasNext, !isLast] : ancestorHasNext;
			walk(child, depth + 1, nextAncestors, childIsLast);
		});
	};
	walk(root, 0, [], true);
	return rows;
}

function countDescendants(node: SessionTreeNode): number {
	let total = 0;
	for (const child of node.children) total += 1 + countDescendants(child);
	return total;
}

function formatTime(isoString: string) {
	const date = new Date(isoString);
	const now = new Date();
	const days = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24));
	if (days === 0) return date.toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });
	if (days === 1) return "Yesterday";
	if (days < 7) return `${days}d ago`;
	return date.toLocaleDateString();
}

export function ForkMapCard({
	root,
	activeSessionId,
	forkingSessionId,
	onLoad,
	onFork,
	onRename,
	onDelete,
}: ForkMapCardProps) {
	const rows = flattenWithGuides(root);
	const forkCount = countDescendants(root);

	return (
		<section className="flex flex-col overflow-hidden rounded-2xl border border-border bg-background shadow-sm">
			<header
				className="flex items-center gap-2 px-3.5 py-2.5"
				style={{ background: "linear-gradient(135deg, var(--accent) 0%, transparent 70%)" }}
			>
				<GitBranch size={15} className="shrink-0 text-primary" />
				<span className="min-w-0 flex-1 truncate text-sm font-semibold text-foreground">{root.session.title}</span>
				<span className="shrink-0 rounded-full bg-primary/15 px-2 py-0.5 text-[10px] font-medium text-primary">
