import { useEffect, useRef, useState } from "react";
import {
	Check,
	Code2,
	Film,
	FlaskConical,
	GitBranch,
	Landmark,
	Languages,
	ListChecks,
	Loader2,
	Map as MapIcon,
	MoreVertical,
	Palette,
	Pencil,
	Sigma,
	Sparkles,
	Trash2,
	X,
} from "lucide-react";
import type { LucideIcon } from "lucide-react";
import type { SessionMetadata } from "../types/session";
import {
	type ArtifactHero,
	type CategoryKey,
	categorize,
	categoryGradient,
} from "./session-card-visuals";

const CATEGORY_ICON: Record<CategoryKey, LucideIcon> = {
	science: FlaskConical,
	"physics-math": Sigma,
	history: Landmark,
	cs: Code2,
	language: Languages,
	arts: Palette,
	general: Sparkles,
};

const HERO_ICON = {
	map: MapIcon,
	animation: Film,
	plan: ListChecks,
} as const;

export interface SessionCardProps {
	session: SessionMetadata;
	hero?: ArtifactHero;
	/** Number of direct forks, shown as a badge when this card stands alone. */
	childCount?: number;
	active?: boolean;
	forking?: boolean;
	justForked?: boolean;
	onLoad: (sessionId: string) => void | Promise<void>;
	onFork: (sessionId: string) => void | Promise<void>;
	onRename: (sessionId: string, title: string) => void | Promise<void>;
	onDelete: (sessionId: string) => void | Promise<void>;
}

function formatDate(isoString: string) {
	const date = new Date(isoString);
	const now = new Date();
	const days = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24));
	if (days === 0) {
		return date.toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });
	}
	if (days === 1) return "Yesterday";
	if (days < 7) return `${days}d ago`;
	return date.toLocaleDateString();
}

export function SessionCard({
	session,
	hero,
	childCount = 0,
	active = false,
	forking = false,
	justForked = false,
	onLoad,
	onFork,
	onRename,
	onDelete,
}: SessionCardProps) {
	const category = categorize(session.title);
	const Icon = CATEGORY_ICON[category.key];
	const [menuOpen, setMenuOpen] = useState(false);
