						</button>
						<button
							type="button"
							role="menuitem"
							className="flex w-full items-center gap-2 px-3 py-2 text-left text-xs hover:bg-accent"
							onClick={() => {
								setMenuOpen(false);
								setConfirmingDelete(false);
